SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Name of ICI", "Control arm", "Cancer type", "Trial name", "Treatment regimen"
FROM clinical_trials
WHERE "Name of ICI" = 'Pembrolizumab' AND "Cancer type" = 'Head and Neck' AND "Control arm" = 'Observation';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Is PD-L1 positivity inclusion criteria", "Class of ICI", "Cancer type", "Name of ICI", "Trial phase"
FROM clinical_trials
WHERE "Cancer type" = 'Head and Neck' AND "Class of ICI" = 'PD-L1, CTLA-4' AND "Is PD-L1 positivity inclusion criteria" = 'No';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Cancer type", "Monotherapy/combination", "Trial phase", "Name of ICI"
FROM clinical_trials
WHERE "Cancer type" = 'Head and Neck' AND "Clinical setting in relation to surgery" = 'Neoadjuvant';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Control arm", "Cancer type", "Control regimen", "Trial phase"
FROM clinical_trials
WHERE "Cancer type" = 'Head and Neck' AND "Control arm" = 'Placebo';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Name of ICI", "Control arm", "Cancer type", "Trial name", "Treatment regimen"
FROM clinical_trials
WHERE "Name of ICI" = 'Chemotherapy' AND "Cancer type" = 'Head and Neck' AND "Control arm" = 'Chemo/Anti-EGFR+Radiotherapy';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Class of ICI", "Cancer type", "Trial phase"
FROM clinical_trials
WHERE "Cancer type" = 'Head and Neck' AND "Class of ICI" = 'CTLA-4' AND "Year" >= 2018;

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Name of ICI", "Follow-up duration for primary endpoint(s) in months | Overall", "Cancer type", "Trial phase"
FROM clinical_trials
WHERE "Cancer type" = 'Head and Neck' AND "Name of ICI" = 'Atezolizumab' AND "Follow-up duration for primary endpoint(s) in months | Overall" > 21;

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Name of ICI", "Monotherapy/combination", "Cancer type", "Type of combination", "Trial phase"
FROM clinical_trials
WHERE "Cancer type" = 'Head and Neck' AND "Name of ICI" = 'Tremelimumab' AND "Monotherapy/combination" = 'Combination';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Trial phase", "Class of ICI", "Monotherapy/combination", "Cancer type", "Name of ICI", "Treatment regimen"
FROM clinical_trials
WHERE "Class of ICI" = 'PD1, CTLA-4' AND "Cancer type" = 'Head and Neck' AND "Trial phase" = 'Phase 2' AND "Monotherapy/combination" = 'Combination';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Control arm", "Cancer type", "Control regimen", "Trial phase"
FROM clinical_trials
WHERE "Cancer type" = 'Head and Neck' AND "Control arm" = 'Radiation';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Control arm", "Cancer type", "Control regimen", "Trial phase"
FROM clinical_trials
WHERE "Cancer type" = 'Head and Neck' AND "Control arm" = 'Best supportive care';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Name of ICI", "Trial phase", "Cancer type", "Trial name", "Treatment regimen"
FROM clinical_trials
WHERE "Name of ICI" = 'Atezolizumab+Trastuzumab emtansine+Placebo' AND "Cancer type" = 'Head and Neck' AND "Trial phase" = 'Phase 3';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Type of combination", "Cancer type", "Treatment regimen", "Trial phase"
FROM clinical_trials
WHERE "Cancer type" = 'Head and Neck' AND "Type of combination" = 'ICI+Vaccine';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Name of ICI", "Trial phase", "Cancer type"
FROM clinical_trials
WHERE "Name of ICI" = 'Chemotherapy' AND "Cancer type" = 'Head and Neck' AND "Trial phase" = 'Phase 3' AND "Originial publication or Follow-up" = 'Follow-up';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Included in MA", "Class of ICI", "Cancer type", "Name of ICI"
FROM clinical_trials
WHERE "Cancer type" = 'Head and Neck' AND "Class of ICI" = 'PD1, CTLA-4' AND "Included in MA" = 'No';
